INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7a37a860-0053-444d-834e-ac1979dd8720', $q$Proposals$q$, $q$Crowdsourced idea submission, amendment, and voting on citizen proposals.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7a37a860-0053-444d-834e-ac1979dd8720', $q$Participatory Budgeting$q$, $q$Citizens allocate real public funds by voting on competing projects.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7a37a860-0053-444d-834e-ac1979dd8720', $q$Secure Elections$q$, $q$Digital voting booth with census upload or token-based voter verification.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7a37a860-0053-444d-834e-ac1979dd8720', $q$Meetings$q$, $q$Schedule and document in-person and online public meetings with minutes.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7a37a860-0053-444d-834e-ac1979dd8720', $q$Assemblies & Processes$q$, $q$Structured, multi-phase participatory spaces for long-running initiatives.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7a37a860-0053-444d-834e-ac1979dd8720', $q$Surveys & Debates$q$, $q$Structured feedback collection and open public discussion tools.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7a37a860-0053-444d-834e-ac1979dd8720', $q$Accountability$q$, $q$Track government follow-through on commitments made during participation.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7a37a860-0053-444d-834e-ac1979dd8720', $q$Self-Hosted & Open Source$q$, $q$AGPL-3.0 Ruby on Rails framework deployable on your own infrastructure with multi-language support.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7a37a860-0053-444d-834e-ac1979dd8720', $q$Completely free and open source under AGPL-3.0, no license fees$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7a37a860-0053-444d-834e-ac1979dd8720', $q$Broad set of built-in democratic tools, including binding elections and participatory budgeting$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7a37a860-0053-444d-834e-ac1979dd8720', $q$Backed by an active nonprofit and global open-governance community$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7a37a860-0053-444d-834e-ac1979dd8720', $q$Full data ownership and control via self-hosting$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7a37a860-0053-444d-834e-ac1979dd8720', $q$Requires Ruby on Rails DevOps expertise to self-host and maintain$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7a37a860-0053-444d-834e-ac1979dd8720', $q$No official managed/hosted SaaS tier from the Decidim Association itself$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7a37a860-0053-444d-834e-ac1979dd8720', $q$Steeper learning curve for administrators than closed-source SaaS competitors$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7a37a860-0053-444d-834e-ac1979dd8720', $q$Design and UX customization requires development resources$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7a37a860-0053-444d-834e-ac1979dd8720', $q$Is Decidim free?$q$, $q$Yes, Decidim is entirely free, open-source software; organizations only pay for hosting and optional support.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7a37a860-0053-444d-834e-ac1979dd8720', $q$Who created Decidim?$q$, $q$Barcelona City Council launched the first Decidim instance in January 2016; it is now governed by the nonprofit Decidim Association.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7a37a860-0053-444d-834e-ac1979dd8720', $q$What license is Decidim released under?$q$, $q$Decidim's source code is released under the AGPL-3.0 license.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7a37a860-0053-444d-834e-ac1979dd8720', $q$Can I self-host Decidim?$q$, $q$Yes, Decidim is designed to be self-hosted on your own infrastructure using Docker and Ruby on Rails deployment guides.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7a37a860-0053-444d-834e-ac1979dd8720', $q$What is Decidim used for?$q$, $q$Participatory budgeting, proposal collection, public deliberation, surveys, assemblies, and secure elections.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7a37a860-0053-444d-834e-ac1979dd8720', $q$Who maintains Decidim today?$q$, $q$The Decidim Association, a nonprofit, alongside a global community of contributors on Metadecidim.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7a37a860-0053-444d-834e-ac1979dd8720', $q$Municipal participatory budgeting$q$, $q$Cities let residents propose and vote on how to allocate portions of the public budget.$q$, $q$City and regional governments$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7a37a860-0053-444d-834e-ac1979dd8720', $q$National or EU-level public consultations$q$, $q$Supranational bodies run large-scale, multilingual citizen consultations on policy.$q$, $q$National ministries and supranational institutions$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7a37a860-0053-444d-834e-ac1979dd8720', $q$University or NGO citizen engagement$q$, $q$Institutions gather structured feedback and run internal democratic processes.$q$, $q$Universities and civil-society organizations$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7a37a860-0053-444d-834e-ac1979dd8720', $q$Self-Hosted (Open Source)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full source code access","AGPL-3.0 license","Unlimited participatory spaces","Community support"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7a37a860-0053-444d-834e-ac1979dd8720', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Decidim is a free and open-source digital platform for participatory democracy, letting governments, universities, and civil-society organizations run structured citizen-participation processes such as proposal collection, budgeting, and voting.$q$, $q$First launched by Barcelona City Council in January 2016 and rewritten as a modular Ruby on Rails framework in 2017, Decidim is now governed by the nonprofit Decidim Association and developed openly by a global community on the Metadecidim platform.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7a37a860-0053-444d-834e-ac1979dd8720', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Decidim's participatory spaces (processes, assemblies, consultations, and initiatives) can be enriched with components including Proposals, Participatory Budgeting, Meetings, Surveys, Debates, Blogs, Accountability, and secure digital Elections.$q$, $q$Because it is self-hosted and released under the AGPL-3.0 license, any organization can deploy, customize, and extend Decidim on its own infrastructure without license fees or vendor lock-in, while remaining obligated to share modifications under the same open license.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7a37a860-0053-444d-834e-ac1979dd8720', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Decidim itself is entirely free software with no licensing cost; organizations pay only for hosting and, optionally, implementation and support services from third-party agencies within the Decidim ecosystem.$q$, $q$This model appeals particularly to public-sector bodies with data-sovereignty or procurement requirements that favor open, auditable civic-tech infrastructure over proprietary SaaS subscriptions.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('7a37a860-0053-444d-834e-ac1979dd8720', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('7a37a860-0053-444d-834e-ac1979dd8720', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('7a37a860-0053-444d-834e-ac1979dd8720', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('7a37a860-0053-444d-834e-ac1979dd8720', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
