INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8ba3ae79-2d46-4049-881a-4cf6417f0f42', $q$Employer of Record (EOR)$q$, $q$Hire full-time employees abroad without setting up a local entity.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8ba3ae79-2d46-4049-881a-4cf6417f0f42', $q$Contractor Management$q$, $q$Compliant contracts and multi-currency payouts in 120+ currencies.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8ba3ae79-2d46-4049-881a-4cf6417f0f42', $q$Global Payroll$q$, $q$Run compliant payroll for your own owned entities in 100+ countries.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8ba3ae79-2d46-4049-881a-4cf6417f0f42', $q$HRIS Dashboard$q$, $q$Unified view of time off, expenses, org charts, and reporting.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8ba3ae79-2d46-4049-881a-4cf6417f0f42', $q$Immigration & Visa Support$q$, $q$Sponsor and manage work visas and employee relocation.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8ba3ae79-2d46-4049-881a-4cf6417f0f42', $q$Equity Management$q$, $q$Issue and manage global equity grants for distributed teams.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8ba3ae79-2d46-4049-881a-4cf6417f0f42', $q$Contractor of Record (COR)$q$, $q$Reduce contractor misclassification risk with a Deel-managed relationship.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8ba3ae79-2d46-4049-881a-4cf6417f0f42', $q$Mobile Apps$q$, $q$iOS and Android apps for managing payroll, time off, and payslips on the go.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8ba3ae79-2d46-4049-881a-4cf6417f0f42', $q$Single platform covering EOR, payroll, contractor payments, and HR in 150+ countries$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8ba3ae79-2d46-4049-881a-4cf6417f0f42', $q$Fast onboarding for international hires, often within days$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8ba3ae79-2d46-4049-881a-4cf6417f0f42', $q$Backed by deep funding ($979M+) and a strong investor base signaling stability$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8ba3ae79-2d46-4049-881a-4cf6417f0f42', $q$Broad currency and payment-method support for global contractor payouts$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8ba3ae79-2d46-4049-881a-4cf6417f0f42', $q$EOR and PEO pricing is significantly higher than pure payroll-only plans$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8ba3ae79-2d46-4049-881a-4cf6417f0f42', $q$Requires a one-month gross salary deposit per EOR employee, tying up cash$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8ba3ae79-2d46-4049-881a-4cf6417f0f42', $q$Currency conversion markup (0.6-2%) adds cost on cross-currency payments$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8ba3ae79-2d46-4049-881a-4cf6417f0f42', $q$Headcount and reported financials vary across sources, making external verification harder$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8ba3ae79-2d46-4049-881a-4cf6417f0f42', $q$What is Deel?$q$, $q$A global platform for Employer of Record, contractor management, payroll, and HR across 150+ countries.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8ba3ae79-2d46-4049-881a-4cf6417f0f42', $q$How much does Deel cost?$q$, $q$Pricing is per-employee or per-contractor, starting around $29/month for payroll and reaching $599-$899/month for EOR.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8ba3ae79-2d46-4049-881a-4cf6417f0f42', $q$What is Employer of Record (EOR)?$q$, $q$A service where Deel's local entity legally employs a worker on a client's behalf in a country where the client has no entity.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8ba3ae79-2d46-4049-881a-4cf6417f0f42', $q$Does Deel replace a legal entity?$q$, $q$For EOR customers, yes; for Global Payroll customers, Deel processes payroll for entities the customer already owns.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8ba3ae79-2d46-4049-881a-4cf6417f0f42', $q$Is Deel publicly traded?$q$, $q$Not yet; Deel filed a confidential S-1 in February 2026 but remains a private company as of this writing.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8ba3ae79-2d46-4049-881a-4cf6417f0f42', $q$What countries does Deel operate in?$q$, $q$Deel supports hiring and payments in more than 150 countries.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8ba3ae79-2d46-4049-881a-4cf6417f0f42', $q$Hiring a full-time employee abroad$q$, $q$Employ a worker in a new country without setting up a local legal entity.$q$, $q$Startups and scaleups expanding internationally$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8ba3ae79-2d46-4049-881a-4cf6417f0f42', $q$Paying a global contractor workforce$q$, $q$Send compliant, multi-currency payments to contractors worldwide.$q$, $q$Agencies and remote-first companies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8ba3ae79-2d46-4049-881a-4cf6417f0f42', $q$Consolidating payroll across owned entities$q$, $q$Run payroll for existing international subsidiaries from one dashboard.$q$, $q$Mid-market and enterprise HR teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8ba3ae79-2d46-4049-881a-4cf6417f0f42', $q$Global Payroll$q$, $q$$29$q$, $q$per employee/month$q$, NULL, $q$["Payroll processing for owned entities","Compliance monitoring","HRIS access"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8ba3ae79-2d46-4049-881a-4cf6417f0f42', $q$Contractor Management$q$, $q$$49$q$, $q$per contractor/month$q$, NULL, $q$["Compliant contracts","Multi-currency payouts in 120+ currencies","Tax form generation"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8ba3ae79-2d46-4049-881a-4cf6417f0f42', $q$Contractor of Record$q$, $q$$325$q$, $q$per contractor/month$q$, NULL, $q$["Reduced misclassification risk","Deel-managed contractor relationship"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8ba3ae79-2d46-4049-881a-4cf6417f0f42', $q$EOR (Standard)$q$, $q$$599$q$, $q$per employee/month$q$, NULL, $q$["Local legal employment","Statutory benefits administration","Tax withholding and filing","24/7 support"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8ba3ae79-2d46-4049-881a-4cf6417f0f42', $q$EOR (Enterprise/high-complexity countries)$q$, $q$$899$q$, $q$per employee/month$q$, NULL, $q$["Local legal employment in higher-complexity jurisdictions","Dedicated support"]$q$::jsonb, 4);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8ba3ae79-2d46-4049-881a-4cf6417f0f42', $q$US PEO$q$, $q$$125$q$, $q$per employee/month$q$, NULL, $q$["US domestic employment","Benefits administration"]$q$::jsonb, 5);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8ba3ae79-2d46-4049-881a-4cf6417f0f42', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Deel is a global hiring and payroll platform that lets companies employ workers in 150+ countries through Employer of Record services, manage international contractors, and run global payroll and HR from one system.$q$, $q$Founded in 2019 by Alex Bouaziz, Deel has raised roughly $979 million and reached a $17.3 billion valuation following its Series E, reporting around $1.4 billion in annual recurring revenue and 35,000+ customers as of 2026.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8ba3ae79-2d46-4049-881a-4cf6417f0f42', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Core products include Employer of Record (EOR), Contractor Management, Contractor of Record, Global Payroll, an HRIS dashboard, immigration support, and equity management, each usable independently or combined.$q$, $q$Deel supports payouts in 120+ currencies, offers 24/7 in-app support, and provides iOS and Android apps so employees and administrators can manage time off, expenses, and payslips from anywhere.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8ba3ae79-2d46-4049-881a-4cf6417f0f42', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Pricing is per-employee or per-contractor and varies by product: Global Payroll starts around $29/month, Contractor Management around $49/month, Contractor of Record around $325/month, and EOR from roughly $599 to $899/month depending on country complexity.$q$, $q$Large enterprise commitments can negotiate lower effective EOR rates, but buyers should budget for a one-month gross-salary deposit per EOR employee and a currency-conversion markup on cross-currency payments.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8ba3ae79-2d46-4049-881a-4cf6417f0f42', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8ba3ae79-2d46-4049-881a-4cf6417f0f42', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8ba3ae79-2d46-4049-881a-4cf6417f0f42', '5e4d4807-cae2-410c-9e7a-df0798a917cb') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8ba3ae79-2d46-4049-881a-4cf6417f0f42', '7336153f-a26b-491c-b927-faf4f5a8d103') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2db08197-cb69-436a-acb8-e03d763b0ab6', $q$DeepSeek-V3$q$, $q$General-purpose LLM with a large (~164K token) context window.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2db08197-cb69-436a-acb8-e03d763b0ab6', $q$DeepSeek-R1$q$, $q$Chain-of-thought reasoning model for math, code, and logic tasks.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2db08197-cb69-436a-acb8-e03d763b0ab6', $q$Free Chat App$q$, $q$Web, iOS, and Android app with a Deep Think reasoning mode.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2db08197-cb69-436a-acb8-e03d763b0ab6', $q$Low-Cost API$q$, $q$Pay-per-token pricing with a 10% cache-hit discount on repeated prompts.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2db08197-cb69-436a-acb8-e03d763b0ab6', $q$Open-Weight Releases$q$, $q$Models are downloadable and self-hostable rather than fully closed.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2db08197-cb69-436a-acb8-e03d763b0ab6', $q$Web Search Integration$q$, $q$Built-in web search inside the chat interface.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2db08197-cb69-436a-acb8-e03d763b0ab6', $q$File Upload & History Sync$q$, $q$Upload documents and sync multi-turn chat history across devices.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2db08197-cb69-436a-acb8-e03d763b0ab6', $q$Multilingual Support$q$, $q$Strong performance across 50+ languages, especially English and Mandarin.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2db08197-cb69-436a-acb8-e03d763b0ab6', $q$Extremely competitive API pricing versus Western frontier labs$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2db08197-cb69-436a-acb8-e03d763b0ab6', $q$Open-weight models allow self-hosting and fine-tuning$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2db08197-cb69-436a-acb8-e03d763b0ab6', $q$Free consumer chat app with a dedicated reasoning mode$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2db08197-cb69-436a-acb8-e03d763b0ab6', $q$Strong benchmark performance on coding and math relative to cost$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2db08197-cb69-436a-acb8-e03d763b0ab6', $q$Data handling and China-based infrastructure raise governance/privacy concerns for some enterprises and governments$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2db08197-cb69-436a-acb8-e03d763b0ab6', $q$Some governments and organizations restrict or ban the official app on official devices$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2db08197-cb69-436a-acb8-e03d763b0ab6', $q$Less mature ecosystem of official enterprise support compared to OpenAI, Anthropic, or Google$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2db08197-cb69-436a-acb8-e03d763b0ab6', $q$Unofficial third-party 'DeepSeek' apps in app stores can mislead users into paying for features the real app offers free$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2db08197-cb69-436a-acb8-e03d763b0ab6', $q$Is DeepSeek free?$q$, $q$The chat app is free; the API is billed per token on a pay-as-you-go basis.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2db08197-cb69-436a-acb8-e03d763b0ab6', $q$Who owns DeepSeek?$q$, $q$DeepSeek is owned and funded by the hedge fund High-Flyer and was founded by Liang Wenfeng.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2db08197-cb69-436a-acb8-e03d763b0ab6', $q$Are DeepSeek models open source?$q$, $q$DeepSeek releases its models as open weights that can be downloaded and self-hosted.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2db08197-cb69-436a-acb8-e03d763b0ab6', $q$What is DeepSeek-R1 used for?$q$, $q$Chain-of-thought reasoning tasks such as math problems, code debugging, and multi-step planning.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2db08197-cb69-436a-acb8-e03d763b0ab6', $q$Is DeepSeek safe to use?$q$, $q$Consumer data is routed through China-based infrastructure, which has led some governments to restrict the official app; self-hosted open-weight deployments avoid that concern.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2db08197-cb69-436a-acb8-e03d763b0ab6', $q$How does DeepSeek pricing compare to OpenAI?$q$, $q$DeepSeek's per-token API pricing is significantly cheaper than comparable OpenAI and Anthropic models.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2db08197-cb69-436a-acb8-e03d763b0ab6', $q$Cost-sensitive AI application development$q$, $q$Build LLM-powered features at a fraction of the token cost of leading closed models.$q$, $q$Startups and independent developers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2db08197-cb69-436a-acb8-e03d763b0ab6', $q$Self-hosted enterprise LLM deployment$q$, $q$Download open weights and run models on private infrastructure for data control.$q$, $q$Enterprises with data-sovereignty requirements$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2db08197-cb69-436a-acb8-e03d763b0ab6', $q$General AI assistant$q$, $q$Use the free chat app for research, writing, and coding help.$q$, $q$Individual consumers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('2db08197-cb69-436a-acb8-e03d763b0ab6', $q$Chat App$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Web, iOS, and Android access","Deep Think reasoning mode","Web search","File upload"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('2db08197-cb69-436a-acb8-e03d763b0ab6', $q$API - DeepSeek-V3$q$, $q$$0.27 per 1M input tokens / $0.40 per 1M output tokens$q$, $q$Pay-as-you-go$q$, NULL, $q$["164K context window","Coding, reasoning, and multilingual tasks"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('2db08197-cb69-436a-acb8-e03d763b0ab6', $q$API - DeepSeek-R1$q$, $q$$0.80 per 1M input/output tokens$q$, $q$Pay-as-you-go$q$, NULL, $q$["Chain-of-thought reasoning","Math and logic tasks"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2db08197-cb69-436a-acb8-e03d763b0ab6', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$DeepSeek is a Chinese AI lab, founded in July 2023 by Liang Wenfeng and funded by the hedge fund High-Flyer, that develops open-weight large language models including DeepSeek-V3 and the reasoning-focused DeepSeek-R1.$q$, $q$DeepSeek rose to global attention in January 2025 when R1 matched leading Western reasoning models like OpenAI's o1 on math, coding, and logic benchmarks at a fraction of the reported training and serving cost.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2db08197-cb69-436a-acb8-e03d763b0ab6', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Models are released with open weights, letting developers self-host and fine-tune them, while a free consumer chat app (web, iOS, Android) offers a Deep Think reasoning mode, web search, and file upload.$q$, $q$The API is priced per token, with DeepSeek-V3 around $0.27/$0.40 per million input/output tokens and R1 around $0.80 per million tokens, plus a caching discount that bills repeated-prompt hits at roughly 10% of the standard input rate.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2db08197-cb69-436a-acb8-e03d763b0ab6', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$The DeepSeek chat app is entirely free to use, while developers pay per token through the API on a pay-as-you-go basis with no subscription commitment.$q$, $q$DeepSeek's API pricing is consistently cited as significantly below comparable OpenAI and Anthropic models, which is central to its positioning as a low-cost, open-weight alternative to closed frontier labs.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('2db08197-cb69-436a-acb8-e03d763b0ab6', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
