INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('717823fe-8010-4821-a2b2-2263a7afbe21', $q$Community Edition requires self-hosting and Django/DevOps expertise to run at scale$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('717823fe-8010-4821-a2b2-2263a7afbe21', $q$Pro tier adds recurring cost ($300/month+) for advanced features$q$, 1);
