INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('717823fe-8010-4821-a2b2-2263a7afbe21', $q$Deduplication tuning may require manual configuration to avoid noise$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('717823fe-8010-4821-a2b2-2263a7afbe21', $q$Is DefectDojo free?$q$, $q$Yes, the Community Edition is free and open source under the BSD 3-Clause license.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('717823fe-8010-4821-a2b2-2263a7afbe21', $q$What is DefectDojo Pro?$q$, $q$A paid, cloud-hosted or on-premises tier adding AI features, enterprise connectors, and support.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('717823fe-8010-4821-a2b2-2263a7afbe21', $q$How many tools does DefectDojo integrate with?$q$, $q$More than 200 security scanning and testing tools.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('717823fe-8010-4821-a2b2-2263a7afbe21', $q$Is DefectDojo an OWASP project?$q$, $q$Yes, DefectDojo is an OWASP Flagship Project.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('717823fe-8010-4821-a2b2-2263a7afbe21', $q$Can I try DefectDojo Pro before buying?$q$, $q$Yes, a two-week trial of DefectDojo Pro is offered.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('717823fe-8010-4821-a2b2-2263a7afbe21', $q$What license does DefectDojo use?$q$, $q$The Community Edition is released under the BSD 3-Clause license.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('717823fe-8010-4821-a2b2-2263a7afbe21', $q$Consolidating multi-scanner vulnerability data$q$, $q$Merge and deduplicate findings from SAST, DAST, SCA, and container scanners.$q$, $q$AppSec and DevSecOps teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('717823fe-8010-4821-a2b2-2263a7afbe21', $q$CI/CD-integrated security automation$q$, $q$Automatically ingest and triage scan results as part of the build pipeline.$q$, $q$Engineering teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('717823fe-8010-4821-a2b2-2263a7afbe21', $q$Compliance and audit reporting$q$, $q$Generate reports demonstrating remediation SLAs and security posture.$q$, $q$Security leadership and GRC teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('717823fe-8010-4821-a2b2-2263a7afbe21', $q$Community Edition$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Self-hosted","200+ tool integrations","Deduplication","REST API"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('717823fe-8010-4821-a2b2-2263a7afbe21', $q$DefectDojo Pro$q$, $q$$300$q$, $q$per month$q$, NULL, $q$["Cloud or on-prem hosting","DefectDojo Sensei AI module","Tunable deduplication rules engine","Enterprise scanner connectors","MCP support"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('717823fe-8010-4821-a2b2-2263a7afbe21', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$DefectDojo is an open-source vulnerability management and ASPM platform that aggregates, deduplicates, and tracks findings from 200+ security testing tools, maintained as an OWASP Flagship Project since its 2013-2015 origins.$q$, $q$Written in Python/Django and licensed under BSD 3-Clause, DefectDojo reports adoption by more than 10,000 organizations and over 45 million downloads of its Community Edition.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('717823fe-8010-4821-a2b2-2263a7afbe21', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The platform normalizes scanner output into products, engagements, tests, and findings, applies deduplication logic across tools and scan runs, and tracks remediation SLAs and compliance reporting.$q$, $q$A commercial Pro tier, available as cloud-hosted SaaS or on-premises from around $300/month, adds the AI-assisted DefectDojo Sensei module, Model Context Protocol support, a tunable deduplication rules engine, and enterprise scanner connectors.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('717823fe-8010-4821-a2b2-2263a7afbe21', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$The Community Edition is completely free and self-hosted, making DefectDojo accessible to teams of any size without per-seat licensing costs.$q$, $q$Organizations that need AI-assisted triage, enterprise scanner integrations, or managed hosting can upgrade to DefectDojo Pro, which is also offered with a two-week trial.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('717823fe-8010-4821-a2b2-2263a7afbe21', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
