INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c3f9f0e9-8131-4e11-ac4b-7ce69fe029a0', $q$Shopify App Store Listing$q$, $q$Native install option for Shopify merchants.$q$, 7);
