INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c3f9f0e9-8131-4e11-ac4b-7ce69fe029a0', $q$What is DelightChat?$q$, $q$An omnichannel helpdesk and WhatsApp marketing platform built for e-commerce brands.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c3f9f0e9-8131-4e11-ac4b-7ce69fe029a0', $q$How much does DelightChat cost?$q$, $q$Plans start around $29-49/month with a 14-day free trial.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c3f9f0e9-8131-4e11-ac4b-7ce69fe029a0', $q$Does DelightChat use the official WhatsApp API?$q$, $q$Yes, it uses Meta's official WhatsApp Business API.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c3f9f0e9-8131-4e11-ac4b-7ce69fe029a0', $q$Is DelightChat only for Shopify?$q$, $q$It has a native Shopify app but also supports other channels and store platforms.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c3f9f0e9-8131-4e11-ac4b-7ce69fe029a0', $q$Who founded DelightChat?$q$, $q$Preetam Nath and Sankalp Jonna founded DelightChat in 2020.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c3f9f0e9-8131-4e11-ac4b-7ce69fe029a0', $q$Does DelightChat support Instagram and Facebook?$q$, $q$Yes, alongside WhatsApp, email, and live chat, all in one inbox.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c3f9f0e9-8131-4e11-ac4b-7ce69fe029a0', $q$Centralizing multi-channel support$q$, $q$Manage WhatsApp, Instagram, and email conversations from one inbox.$q$, $q$E-commerce support teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c3f9f0e9-8131-4e11-ac4b-7ce69fe029a0', $q$Recovering abandoned carts via WhatsApp$q$, $q$Automate WhatsApp messages to win back abandoned checkouts.$q$, $q$D2C marketing teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c3f9f0e9-8131-4e11-ac4b-7ce69fe029a0', $q$Automating order and shipping notifications$q$, $q$Send automated WhatsApp updates tied to Shopify order status.$q$, $q$Shopify merchants$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c3f9f0e9-8131-4e11-ac4b-7ce69fe029a0', $q$Startup$q$, $q$$29$q$, $q$per month$q$, NULL, $q$["Shared team inbox","WhatsApp, Instagram, and email channels","Basic automation"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c3f9f0e9-8131-4e11-ac4b-7ce69fe029a0', $q$Scale$q$, $q$$99$q$, $q$per month$q$, NULL, $q$["Increased conversation limits","More team seats","WhatsApp broadcast campaigns"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c3f9f0e9-8131-4e11-ac4b-7ce69fe029a0', $q$Growth$q$, $q$$299$q$, $q$per month$q$, NULL, $q$["Full automation suite","Advanced WhatsApp marketing","Priority support"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c3f9f0e9-8131-4e11-ac4b-7ce69fe029a0', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$DelightChat is an omnichannel helpdesk and WhatsApp marketing platform built for D2C and e-commerce SMEs, founded in 2020 by Preetam Nath and Sankalp Jonna.$q$, $q$It unifies the WhatsApp Business API, Instagram, Facebook, email, and live chat into one team inbox, with tight Shopify integration that surfaces order data directly inside conversations.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c3f9f0e9-8131-4e11-ac4b-7ce69fe029a0', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The Helpdesk half centralizes multi-channel conversations with assignment rules and canned responses, while the Marketing half uses the official WhatsApp Business API for broadcast campaigns, abandoned-cart recovery, and shipping notifications.$q$, $q$An AI chatbot handles first-response automation across channels before escalating to human agents, and the product is available as a web app plus a native Shopify App Store listing.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c3f9f0e9-8131-4e11-ac4b-7ce69fe029a0', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Plans are tiered at roughly $29 (Startup), $99 (Scale), and $299 (Growth) per month, with a 14-day free trial available before committing to a paid plan.$q$, $q$Pricing scales with conversation volume, team seats, and automation depth, positioning DelightChat as an affordable alternative to enterprise helpdesk suites for growing e-commerce brands.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c3f9f0e9-8131-4e11-ac4b-7ce69fe029a0', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c3f9f0e9-8131-4e11-ac4b-7ce69fe029a0', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
