INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a4888a56-3678-4b59-b919-440fd6bf1847', $q$Client/Daemon Architecture$q$, $q$Run the core torrent engine headlessly and control it remotely.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a4888a56-3678-4b59-b919-440fd6bf1847', $q$Web UI$q$, $q$Manage torrents from any browser on any device.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a4888a56-3678-4b59-b919-440fd6bf1847', $q$Console Interface$q$, $q$Manage torrents over SSH or terminal on headless servers.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a4888a56-3678-4b59-b919-440fd6bf1847', $q$Magnet Link Support$q$, $q$Full magnet URI support since version 1.1.0.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a4888a56-3678-4b59-b919-440fd6bf1847', $q$DHT, PEX, UPnP, NAT-PMP$q$, $q$Trackerless discovery and automatic port forwarding.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a4888a56-3678-4b59-b919-440fd6bf1847', $q$Protocol Encryption$q$, $q$Obfuscate BitTorrent traffic for privacy and ISP throttling avoidance.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a4888a56-3678-4b59-b919-440fd6bf1847', $q$Plugin System$q$, $q$RSS auto-download, scheduling, labels, and community-built extensions.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a4888a56-3678-4b59-b919-440fd6bf1847', $q$Cross-Platform$q$, $q$Native support for Linux, with builds for Windows and macOS.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a4888a56-3678-4b59-b919-440fd6bf1847', $q$Completely free and open source with no ads or paid tiers$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a4888a56-3678-4b59-b919-440fd6bf1847', $q$Lightweight core with a flexible plugin system for advanced features$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a4888a56-3678-4b59-b919-440fd6bf1847', $q$Client/daemon split makes it ideal for headless servers, NAS, and seedboxes$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a4888a56-3678-4b59-b919-440fd6bf1847', $q$Actively translated into dozens of languages by a volunteer community$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a4888a56-3678-4b59-b919-440fd6bf1847', $q$Interface feels dated compared to some modern competitors like qBittorrent$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a4888a56-3678-4b59-b919-440fd6bf1847', $q$Development pace has historically been slower and less consistent than top rivals$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a4888a56-3678-4b59-b919-440fd6bf1847', $q$Best experience is on Linux; Windows and macOS builds have lagged at times$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a4888a56-3678-4b59-b919-440fd6bf1847', $q$Advanced features require installing and configuring separate plugins$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a4888a56-3678-4b59-b919-440fd6bf1847', $q$Is Deluge free?$q$, $q$Yes, Deluge is fully free and open source under GPL-3.0-or-later.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a4888a56-3678-4b59-b919-440fd6bf1847', $q$What platforms does Deluge support?$q$, $q$Linux, Windows, and macOS.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a4888a56-3678-4b59-b919-440fd6bf1847', $q$Can I run Deluge on a headless server?$q$, $q$Yes, via the daemon combined with the Web UI or console interface.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a4888a56-3678-4b59-b919-440fd6bf1847', $q$Does Deluge support magnet links?$q$, $q$Yes, since version 1.1.0 released in January 2009.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a4888a56-3678-4b59-b919-440fd6bf1847', $q$What underlying library does Deluge use?$q$, $q$libtorrent, a C++ BitTorrent networking library.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a4888a56-3678-4b59-b919-440fd6bf1847', $q$How is Deluge different from qBittorrent?$q$, $q$Both are free and open source; Deluge's key distinction is its dedicated daemon/remote-UI architecture.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a4888a56-3678-4b59-b919-440fd6bf1847', $q$Running a headless torrent box$q$, $q$Operate Deluge on a home server or NAS and manage it remotely.$q$, $q$Self-hosters and power users$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a4888a56-3678-4b59-b919-440fd6bf1847', $q$Managing downloads via Web UI$q$, $q$Control torrents from any browser without a desktop client.$q$, $q$Users wanting browser-based remote control$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a4888a56-3678-4b59-b919-440fd6bf1847', $q$Lightweight desktop torrenting$q$, $q$Use the native GTK client for everyday torrent downloads on Linux.$q$, $q$Privacy-conscious individual users$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('a4888a56-3678-4b59-b919-440fd6bf1847', $q$Open Source$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full client and daemon access","All official plugins","Community support"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a4888a56-3678-4b59-b919-440fd6bf1847', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Deluge is a free, open-source, cross-platform BitTorrent client first released in 2006 and licensed under GPL-3.0-or-later, developed by a volunteer community rather than a company.$q$, $q$Built on the libtorrent networking library, Deluge splits its core torrent engine into a background daemon that can be controlled remotely by a GTK desktop GUI, a text console, or a browser-based Web UI.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a4888a56-3678-4b59-b919-440fd6bf1847', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Deluge supports magnet links, DHT, peer exchange, protocol encryption, UPnP, NAT-PMP, and web seeds, with additional capabilities like RSS auto-downloading and bandwidth scheduling available through its official plugin system.$q$, $q$Its client/daemon architecture makes it especially well suited to headless servers, NAS devices, and seedboxes, where users manage transfers remotely without running a full desktop environment.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a4888a56-3678-4b59-b919-440fd6bf1847', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Deluge is entirely free with no paid tiers, ads, or telemetry-driven monetization, consistent with its GPL open-source licensing.$q$, $q$Its closest free competitor is qBittorrent, while paid or ad-supported clients like uTorrent gate certain features behind subscriptions that Deluge does not require.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('a4888a56-3678-4b59-b919-440fd6bf1847', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('a4888a56-3678-4b59-b919-440fd6bf1847', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
