INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4414714c-18c2-421d-a443-5f73b6e567de', $q$No-Download Browser Experience$q$, $q$Hosts and attendees join webinars directly through a web browser.$q$, 0);
