INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4414714c-18c2-421d-a443-5f73b6e567de', $q$Featured Actions$q$, $q$Surface in-webinar calls-to-action and offers at chosen moments.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4414714c-18c2-421d-a443-5f73b6e567de', $q$Interactive Engagement Tools$q$, $q$Polls, chat, Q&A, reactions, and downloadable handouts.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4414714c-18c2-421d-a443-5f73b6e567de', $q$Registration & Reminder Automation$q$, $q$Built-in registration pages and automated reminder emails.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4414714c-18c2-421d-a443-5f73b6e567de', $q$Registration-Source Analytics$q$, $q$Track which marketing channels drive webinar attendance.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4414714c-18c2-421d-a443-5f73b6e567de', $q$Marketing & CRM Integrations$q$, $q$Sync registrant and attendee data with email and CRM platforms.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4414714c-18c2-421d-a443-5f73b6e567de', $q$Custom Branding$q$, $q$White-label registration pages and webinar rooms on Growth+ plans.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4414714c-18c2-421d-a443-5f73b6e567de', $q$Fully browser-based, no-download experience improves attendee show-up rates$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4414714c-18c2-421d-a443-5f73b6e567de', $q$Rich built-in engagement tools purpose-built for marketing webinars$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4414714c-18c2-421d-a443-5f73b6e567de', $q$Supports live, automated, and evergreen formats in one platform$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4414714c-18c2-421d-a443-5f73b6e567de', $q$14-day free trial available to test before purchasing$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4414714c-18c2-421d-a443-5f73b6e567de', $q$Automated and evergreen webinars require upgrading to the Growth plan or higher$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4414714c-18c2-421d-a443-5f73b6e567de', $q$Smaller attendee room sizes on entry-level plans compared to enterprise webinar tools$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4414714c-18c2-421d-a443-5f73b6e567de', $q$Less suited to massive, broadcast-scale events than platforms like Zoom Events$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4414714c-18c2-421d-a443-5f73b6e567de', $q$Now part of a larger holding company (Banzai), which has meant product bundling changes since the 2021 acquisition$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4414714c-18c2-421d-a443-5f73b6e567de', $q$What is Demio?$q$, $q$A browser-based webinar platform built for marketing teams.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4414714c-18c2-421d-a443-5f73b6e567de', $q$How much does Demio cost?$q$, $q$Plans start around $45/month when billed annually.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4414714c-18c2-421d-a443-5f73b6e567de', $q$Does Demio require software downloads?$q$, $q$No, Demio runs entirely in the browser for hosts and attendees.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4414714c-18c2-421d-a443-5f73b6e567de', $q$Does Demio support automated or evergreen webinars?$q$, $q$Yes, from the Growth plan upward.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4414714c-18c2-421d-a443-5f73b6e567de', $q$Who owns Demio?$q$, $q$Banzai International, Inc., following a 2021 acquisition.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4414714c-18c2-421d-a443-5f73b6e567de', $q$Is there a free trial?$q$, $q$Yes, Demio offers a 14-day free trial.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4414714c-18c2-421d-a443-5f73b6e567de', $q$Running lead-generation product webinars$q$, $q$Host live product demos and Q&A sessions to generate sales leads.$q$, $q$B2B marketing teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4414714c-18c2-421d-a443-5f73b6e567de', $q$Automating an evergreen webinar funnel$q$, $q$Replay a top-performing webinar on a recurring schedule to keep generating leads.$q$, $q$Demand generation teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4414714c-18c2-421d-a443-5f73b6e567de', $q$Hosting customer education sessions$q$, $q$Run onboarding and product-training webinars for customers.$q$, $q$Customer success teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4414714c-18c2-421d-a443-5f73b6e567de', $q$Starter$q$, $q$$45$q$, $q$per month (billed annually)$q$, NULL, $q$["Up to 50 attendees","1 host","Live webinars","Engagement tools"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4414714c-18c2-421d-a443-5f73b6e567de', $q$Growth$q$, $q$$75$q$, $q$per host/month (billed annually)$q$, NULL, $q$["Up to 150 attendees","Automated and evergreen webinars","Registration-source analytics","Custom branding"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4414714c-18c2-421d-a443-5f73b6e567de', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Demio is a browser-based webinar platform for marketers, founded in 2014-2015 by Wyatt Jozwowski and David Abrams and acquired by Banzai International, Inc. in early 2021.$q$, $q$Its core design principle is a no-download, fully in-browser experience for both hosts and attendees, aimed at maximizing webinar show-up rates.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4414714c-18c2-421d-a443-5f73b6e567de', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Demio supports live, automated, and evergreen webinars, with built-in engagement tools including polls, chat, Q&A, reactions, handouts, and Featured Actions for in-webinar calls-to-action.$q$, $q$Registration-source analytics and marketing/CRM integrations help teams track which channels drive attendance, while custom branding controls unlock on higher-tier plans.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4414714c-18c2-421d-a443-5f73b6e567de', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$The Starter plan begins around $45/month (billed annually) for a 50-attendee room with one host, while the Growth plan, from around $75/host/month, unlocks automated and evergreen webinars plus deeper analytics.$q$, $q$A 14-day free trial lets teams test the live-webinar experience before subscribing, and larger attendee capacities are available on higher, more custom-priced tiers.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('4414714c-18c2-421d-a443-5f73b6e567de', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('4414714c-18c2-421d-a443-5f73b6e567de', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
