INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b102eee5-b364-47b7-9569-b256d99e7549', $q$High-Availability v5 Architecture$q$, $q$Stateless, active/active scaling coordinated through PostgreSQL.$q$, 5);
