INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b102eee5-b364-47b7-9569-b256d99e7549', $q$Multi-Project Portfolio View$q$, $q$Track components across every version of every project in one place.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b102eee5-b364-47b7-9569-b256d99e7549', $q$Completely free and open source under the permissive Apache 2.0 license$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b102eee5-b364-47b7-9569-b256d99e7549', $q$Purpose-built for continuous, SBOM-based monitoring rather than one-off scans$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b102eee5-b364-47b7-9569-b256d99e7549', $q$Backed by OWASP's vendor-neutral, nonprofit governance$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b102eee5-b364-47b7-9569-b256d99e7549', $q$Proven to scale to enterprise-size portfolios (250,000+ SBOMs in production reports)$q$, 3);
