INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b102eee5-b364-47b7-9569-b256d99e7549', $q$Is Dependency-Track free?$q$, $q$Yes, it is free and open source under the Apache 2.0 license.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b102eee5-b364-47b7-9569-b256d99e7549', $q$What is an SBOM?$q$, $q$A Software Bill of Materials, a structured list of all components in a software project.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b102eee5-b364-47b7-9569-b256d99e7549', $q$Who maintains Dependency-Track?$q$, $q$The OWASP Foundation and its open-source contributor community.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b102eee5-b364-47b7-9569-b256d99e7549', $q$What SBOM format does Dependency-Track use?$q$, $q$CycloneDX, an OWASP-originated, internationally standardized SBOM format.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b102eee5-b364-47b7-9569-b256d99e7549', $q$Can Dependency-Track integrate with CI/CD?$q$, $q$Yes, via its REST API for automated SBOM ingestion.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b102eee5-b364-47b7-9569-b256d99e7549', $q$How is Dependency-Track different from DefectDojo?$q$, $q$Dependency-Track focuses specifically on SBOM-based component and vulnerability tracking, while DefectDojo aggregates findings across many types of security tools.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b102eee5-b364-47b7-9569-b256d99e7549', $q$Continuous open-source component risk monitoring$q$, $q$Track vulnerabilities across every project and dependency version automatically.$q$, $q$AppSec and DevSecOps teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b102eee5-b364-47b7-9569-b256d99e7549', $q$Meeting SBOM compliance requirements$q$, $q$Produce and manage SBOMs required by regulatory or procurement mandates.$q$, $q$Regulated software vendors$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b102eee5-b364-47b7-9569-b256d99e7549', $q$Portfolio-wide supply chain risk visibility$q$, $q$Give security leadership a single view of component risk across the organization.$q$, $q$Enterprise security leadership$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b102eee5-b364-47b7-9569-b256d99e7549', $q$Open Source$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Self-hosted deployment","Unlimited SBOM ingestion","EPSS prioritization","REST API"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b102eee5-b364-47b7-9569-b256d99e7549', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Dependency-Track is a free, open-source OWASP Flagship Project for software supply chain security, originating in 2013 and licensed under Apache 2.0.$q$, $q$It centers on the Software Bill of Materials (SBOM) as its unit of truth, ingesting CycloneDX SBOMs to continuously track components across every version of every project in an organization's portfolio.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b102eee5-b364-47b7-9569-b256d99e7549', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The platform continuously cross-references components against multiple vulnerability sources, prioritizes remediation using EPSS exploitability scores, and produces/consumes CycloneDX VEX and VDR documents.$q$, $q$Its redesigned v5 engine runs stateless instances coordinating through PostgreSQL alone, enabling active/active high-availability deployments that have been reported handling 250,000+ SBOMs and tens of millions of components in production.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b102eee5-b364-47b7-9569-b256d99e7549', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Dependency-Track is completely free and self-hosted, with no official commercial SaaS tier or licensing cost from the OWASP Foundation.$q$, $q$Organizations needing managed hosting or commercial support typically work with third-party vendors in the OWASP ecosystem rather than a single official vendor.$q$]::text[], 2);
